# torch_ios: PIL._imaging minimal functional stub for iOS.
#
# Upstream _imaging is a C extension we haven't cross-compiled for iOS.
# For manim's cairo_renderer.scene_finished() → save_image() flow we only
# need a MINIMAL image-backing object that can hold a numpy RGBA buffer
# and save it to PNG. We implement that with pycairo's ImageSurface
# (which IS built for iOS), so "final frame PNG" output actually works.

try:
    from PIL import _version as _pil_version
    PILLOW_VERSION = _pil_version.__version__
except Exception:
    PILLOW_VERSION = "12.1.1"


# JPEG encoder strategies referenced at PIL/Image.py module level.
DEFAULT_STRATEGY = 0
FILTERED = 1
HUFFMAN_ONLY = 2
RLE = 3
FIXED = 4

# Transpose constants
NONE = 0
FLIP_LEFT_RIGHT = 0
FLIP_TOP_BOTTOM = 1
ROTATE_90 = 2
ROTATE_180 = 3
ROTATE_270 = 4
TRANSPOSE = 5
TRANSVERSE = 6


class ImagingCore:
    """Minimal Imaging-core replacement backed by a raw RGBA buffer.
    Pillow's Image.new / frombuffer / fromarray all call core.fill/new to
    allocate; manim's save_image path then calls .save(path) on the
    returned Image, which pushes pixel data through here. We accept
    pixel data and save via pycairo's ImageSurface.write_to_png."""

    def __init__(self, mode, size, data=None):
        self.mode = mode or "RGBA"
        self.size = tuple(size)
        self.pixel_access = None
        width, height = self.size
        # Buffer size: 4 bytes per pixel for RGB/RGBA modes, 1 for L
        bpp = 4 if self.mode.upper() in ("RGBA", "RGB", "BGRA", "BGR", "ARGB") else 1
        self._bpp = bpp
        self._data = bytearray(width * height * bpp) if data is None else bytearray(data)

    # Pillow calls these a lot but we can return self or stub
    def convert(self, mode, *args, **kwargs):
        new_core = ImagingCore(mode, self.size)
        # Best effort: if same mode, copy; else zero-fill (not accurate but doesn't crash)
        if mode == self.mode and len(new_core._data) == len(self._data):
            new_core._data[:] = self._data
        return new_core

    def resize(self, size, *args, **kwargs):
        return ImagingCore(self.mode, size)

    def crop(self, box):
        x0, y0, x1, y1 = box
        return ImagingCore(self.mode, (x1 - x0, y1 - y0))

    def paste(self, *args, **kwargs):
        return None

    def tobytes(self, *args, **kwargs):
        return bytes(self._data)

    def getbands(self):
        if self.mode.upper() == "RGBA":
            return ("R", "G", "B", "A")
        if self.mode.upper() == "RGB":
            return ("R", "G", "B")
        return (self.mode,)

    # Pillow's Image.save delegates to the plugin's _save which calls
    # into core. We intercept at a higher level in PIL/Image.py via
    # monkey-patch below, but provide this as a fallback.
    def save(self, fp, fmt=None):
        self._save_png(fp)

    def _save_png(self, fp):
        """Write the buffer as a PNG via pycairo."""
        import cairo
        w, h = self.size
        stride = cairo.ImageSurface.format_stride_for_width(cairo.FORMAT_ARGB32, w)
        # Cairo FORMAT_ARGB32 is 4 bytes per pixel, premultiplied
        # Our buffer is raw RGBA; convert to ARGB (Cairo on Apple = BGRA in memory)
        buf = bytearray(stride * h)
        for y in range(h):
            for x in range(w):
                i = (y * w + x) * 4
                r, g, b, a = self._data[i], self._data[i+1], self._data[i+2], self._data[i+3]
                j = y * stride + x * 4
                # FORMAT_ARGB32 on little-endian: BGRA in memory
                buf[j + 0] = b
                buf[j + 1] = g
                buf[j + 2] = r
                buf[j + 3] = a
        surface = cairo.ImageSurface.create_for_data(
            memoryview(buf), cairo.FORMAT_ARGB32, w, h, stride
        )
        if hasattr(fp, "write"):
            # fp is a file-like; cairo writes to path, so go via temp
            import tempfile, os as _os
            tf = tempfile.NamedTemporaryFile(delete=False, suffix=".png")
            tf.close()
            surface.write_to_png(tf.name)
            with open(tf.name, "rb") as _r:
                fp.write(_r.read())
            _os.unlink(tf.name)
        else:
            surface.write_to_png(str(fp))


class ImagingDecoder:
    pass
class ImagingEncoder:
    pass


# ─── Factory functions PIL/Image.py calls ─────────────────────────────
def new(mode, size, color=None):
    """Create a new ImagingCore; optionally fill with a solid color."""
    c = ImagingCore(mode, size)
    if color is not None:
        # Handle integer colors + tuple colors
        if isinstance(color, (int, float)):
            color = (int(color),) * c._bpp
        elif isinstance(color, tuple) and len(color) < c._bpp:
            color = color + (255,) * (c._bpp - len(color))
        if isinstance(color, tuple):
            w, h = size
            for i in range(w * h):
                for k in range(c._bpp):
                    c._data[i * c._bpp + k] = int(color[k]) & 0xFF
    return c


fill = new  # alias — PIL/Image.py's `new()` calls `core.fill(mode, size, color)`


def frombuffer(mode, size, data, decoder_name, args, orientation=0, upper_left=0):
    """Wrap an existing bytes buffer as an ImagingCore."""
    return ImagingCore(mode, size, data=data)


def frombytes(mode, size, data, decoder_name="raw", args=None):
    return ImagingCore(mode, size, data=data)


# PIL's Image.open plugin machinery calls `core.open(...)` etc. — we don't
# support reading image files; the rest of manim doesn't need this path.
def open(*args, **kwargs):
    raise NotImplementedError("PIL._imaging.open: cannot read image files on iOS stub")


def __getattr__(name):
    # Unknown attributes → a permissive callable that returns a fresh
    # ImagingCore rather than raising, so edge-case Pillow code paths
    # don't crash on import-time lookups.
    def _perm(*args, **kwargs):
        raise NotImplementedError(f"PIL._imaging.{name}: not supported in iOS stub")
    return _perm
